class Solution {
public:
    int countNumbers(string l, string r, int b) {
        const int MOD = 1e9 + 7;
        int count = 0;
        for (long long num = stoll(l); num <= stoll(r); num++) {
            string str = "";
            long long n = num;
            while (n > 0) {
                str = to_string(n % b) + str;
                n /= b;
            }
            bool valid = true;
            for (int i = 1; i < str.size(); i++) {
                if (str[i] < str[i - 1]) {
                    valid = false;
                    break;
                }
            }
            if (valid) count = (count + 1) % MOD;
        }
        return count;
    }
};

